function Invoke-GitChecked {
  & git @args
  if ($LASTEXITCODE -ne 0) { throw "git $($args -join ' ') failed" }
}

function Invoke-GitYoloPush {
  param([string]$Branch)

  $upstream = & git rev-parse --abbrev-ref --symbolic-full-name '@{u}' 2>$null
  $hasUpstream = $LASTEXITCODE -eq 0 -and -not [string]::IsNullOrWhiteSpace($upstream)

  if ($hasUpstream) {
    & git push
    if ($LASTEXITCODE -ne 0) {
      Invoke-GitChecked push --force
    }
  } else {
    & git push --set-upstream origin $Branch
    if ($LASTEXITCODE -ne 0) {
      Invoke-GitChecked push --set-upstream --force origin $Branch
    }
  }
}

function Invoke-GitYoloMain {
  $branch = (& git branch --show-current).Trim()
  if ($LASTEXITCODE -ne 0 -or [string]::IsNullOrWhiteSpace($branch)) { throw "Not on a branch." }

  $dirty = & git status --porcelain
  if ($LASTEXITCODE -ne 0) { throw "git status failed" }
  if ($dirty) {
    Invoke-GitChecked add -A
    $staged = & git diff --cached --name-only
    if ($LASTEXITCODE -ne 0) { throw "git diff --cached failed" }
    if ($staged) {
      Invoke-GitChecked commit -m "chore: yolo update"
    }
  }

  Invoke-GitYoloPush -Branch $branch
  Invoke-GitChecked status --short
}

Invoke-GitYoloMain
